import{_ as t,o as a,c as o,a3 as n}from"./chunks/framework.BveOjhN0.js";const m=JSON.parse('{"title":"Payment Gateways — User Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Payment Gateways — User Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/user-guide/payment-gateways"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Payment Gateways — User Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/user-guide/payment-gateways"}]]},"headers":[],"relativePath":"user-guide/payment-gateways.md","filePath":"user-guide/payment-gateways.md","lastUpdated":1784157157000}'),s={name:"user-guide/payment-gateways.md"};function r(i,e,l,d,g,c){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="payment-gateways-—-user-guide" tabindex="-1">Payment Gateways — User Guide <a class="header-anchor" href="#payment-gateways-—-user-guide" aria-label="Permalink to &quot;Payment Gateways — User Guide&quot;">​</a></h1><p>Central admins manage payment providers under the top-level <strong>Billing</strong> menu (not Settings).</p><h2 id="where-to-go" tabindex="-1">Where to go <a class="header-anchor" href="#where-to-go" aria-label="Permalink to &quot;Where to go&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Menu item</th><th>Purpose</th></tr></thead><tbody><tr><td>Billing Dashboard</td><td>Snapshot of invoices, payments, and default gateway</td></tr><tr><td>Invoices / Payments</td><td>Platform ledgers</td></tr><tr><td>Payment Gateways</td><td>Enable, configure, test, and monitor providers</td></tr><tr><td>Transactions / Refunds / Payment Methods / Coupons / Taxes / Billing Logs</td><td>Reserved Billing screens (expanding)</td></tr></tbody></table><p>Settings → Billing still holds invoice prefix / trial toggles — <strong>not</strong> gateway credentials.</p><h2 id="managing-a-gateway" tabindex="-1">Managing a gateway <a class="header-anchor" href="#managing-a-gateway" aria-label="Permalink to &quot;Managing a gateway&quot;">​</a></h2><ol><li>Open <strong>Billing → Payment Gateways</strong>.</li><li>Use row actions: <ul><li><strong>View details</strong> — capabilities, currencies, webhook status, recent logs</li><li><strong>Configure</strong> — enter credentials (Stripe: publishable/secret/webhook; Creem: API secret + webhook secret)</li><li><strong>Product mapping</strong> — map catalog modules to provider product/price references (Stripe <code>price_…</code> / Creem <code>prod_…</code>). Module create/edit does <strong>not</strong> collect provider IDs.</li><li><strong>Test connection</strong> — verifies credentials against the provider</li><li><strong>Set as default</strong> — used for new checkouts / consolidated billing</li><li><strong>Enable / Disable</strong> — disabled gateways cannot process (cannot disable the current default)</li></ul></li><li>Switch <strong>Sandbox / Live</strong> from the details dialog.</li></ol><p>Secrets are write-only in the UI. After save, the screen only shows whether a secret is configured.</p><h2 id="defaults" tabindex="-1">Defaults <a class="header-anchor" href="#defaults" aria-label="Permalink to &quot;Defaults&quot;">​</a></h2><p>The platform default gateway drives <code>BillingEngine</code> checkout selection. Changing default updates the <code>default_payment_gateway</code> system setting and the gateway’s <code>is_default</code> flag.</p>',10)])])}const u=t(s,[["render",r]]);export{m as __pageData,u as default};
